var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"다들, 괜찮습니까?","JPN":"皆さん、ご無事ですか？","ENG":"Is everyone okay?","TWN":"大家都還好嗎？"},"stage":{"bg":"HANGAR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"다, 당신! 우릴 꼬드겨서 캠프에 불러온 사람이잖아!","JPN":"あ、あんた！　私たちをそそのかしてキャンプに呼んだ人じゃない！","ENG":"Y-you! You’re the one who tricked us into coming to the camp!","TWN":"你…你！你不就是把我們哄騙到體驗營的人嗎！"},"stage":{"bg":"HANGAR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"책임져! 책임져요! 전 놀고 먹으면서 지원금을 받으러 온 거지 괴물 군인들과 싸우러 온 게 아니라고요!","JPN":"責任取って！　責任取りなさいよ！　私は食べたり遊んだりしながら支援金をもらいに来ただけで、化け物の軍人と戦うために来たわけじゃないんです！","ENG":"This is all your fault! You’re responsible for all of this! I came here to have fun while getting paid, not to fight those monstrous soldiers!","TWN":"你要負責！快負責！我來這邊是吃吃喝喝，賺支援金的，才不是來和怪物軍人打架的！"},"stage":{"bg":"HANGAR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L8_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"괴물 군인이라니, 그건 또 무슨 말입니까?","JPN":"化け物の軍人だなんて、それはまた何ですか？","ENG":"Monstrous soldiers? What do you mean?","TWN":"什麼怪物軍人？你在說什麼？"},"stage":{"bg":"HANGAR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"그, 그게…… 우리가 자꾸 도망가니까 이상한 괴물로 변해서 막 쫓아오더라고요……","JPN":"そ、それが……私たちが逃げ続けたら、変な化け物になって追ってきたんですよ……","ENG":"A-as we kept running away, they suddenly transformed into strange monsters and kept chasing us...","TWN":"就是……我們一直逃，他們就一直變成奇怪的怪物追上來……"},"stage":{"bg":"HANGAR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"맞아! 꼭 침식체 같긴 한데 그 중에서도 처음 보는 모습이었다니까.","JPN":"そうだ！　まるで侵食体みたいだが、そのなかでも初めて見る姿だったぞ。","ENG":"She’s telling the truth! They seem to be Corrupted Objects, but I’ve never seen anything like them before.","TWN":"是啊！好像是侵蝕體，但有些跟之前看過的又不太一樣。"},"stage":{"bg":"HANGAR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"내 각성 탄환도 통하지 않았어. 제길, 아마 말로만 듣던 4종 침식체가 아닐까?","JPN":"俺の覚醒弾も通じなかった。くっそ、これが噂で聞いた第4種侵食体ってやつなんじゃねえか？","ENG":"Not even my awakened bullets work on them. Damn it, could they be the rumored Category 4 Corrupted Objects?","TWN":"我的覺醒子彈對他們也無效，該死！難道是傳聞中的4類侵蝕體？"},"stage":{"bg":"HANGAR","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"아니, 개별 침식파는 그리 높지 않아.","JPN":"いいや、個別の侵食波はそこまで高くはない。","ENG":"No, their individual Corruption Ray levels aren’t that high.","TWN":"不，他們的侵蝕波不高。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L18_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"다만 거대한 의식 네트워크에 연결되어 본래 이상의 힘을 발휘할 수 있는 특수한 침식체 아종이다.","JPN":"ただ巨大な意識ネットワークに繋げられ、本来以上の力を発揮できる特殊な侵食体の亜種だ。","ENG":"However, they are a special Corrupted Object subspecies that have intense strength beyond their original limits by being connected to a large network of consciousness.","TWN":"他們是連結到一個巨大的意識網路後，便可以發揮超出原本力量的特殊侵蝕體亞種。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당신은……? 어떻게 그런 걸 아는 거죠?","JPN":"あなたは……？　どうしてそんなことを知っているのですか？","ENG":"Huh...? How do you know this?","TWN":"你是……怎麼知道這些的？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"데이터베이스에 등록되어 있는 가능성들 중 하나였으니까.","JPN":"データベースに登録されている、可能性の一つだったから。","ENG":"It’s one of the probabilities registered in the database.","TWN":"這是紀錄在資料庫裡的其中一個可能性。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"데이터베이스?","JPN":"データベース？","ENG":"Database?","TWN":"資料庫？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_CHIEF","text":{"KOREA":"아직도 포기하지 않고 있나?","JPN":"まだ諦めていないのか？","ENG":"You still haven’t given up yet?","TWN":"還是堅決不投降嗎？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_CHIEF","face":"UNIT_IDLE"},"R":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L28_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_CHIEF","text":{"KOREA":"델타세븐 부대원들에게 경고한다. 즉시 항복하고 체포에 응해라.","JPN":"デルタセブンの部隊員に警告する。ただちに降伏し、逮捕に応じろ。","ENG":"This is a warning to all Delta Seven unit members. Surrender immediately and turn yourselves in for arrest.","TWN":"警告第七三角洲部隊的隊員，立刻棄械投降！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_CHIEF","face":"UNIT_IDLE"},"R":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_CHIEF","text":{"KOREA":"너희들에게 승산은 없다. 이것은 마지막 경고다.","JPN":"貴様らに勝算はない。これは最後の警告だ。","ENG":"You have no chance of winning. This is your last warning.","TWN":"你們是沒有勝算的，這是最後一次警告！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_CHIEF","face":"UNIT_IDLE"},"R":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"당신들이야말로 즉시 공격을 멈추고 물러서십시오!","JPN":"あなたたちこそ今すぐ攻撃を止め、退いてください！","ENG":"You are the ones who should cease your attack immediately and stand down!","TWN":"我才要勸你們立刻撤退，停止攻擊！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L32_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"어째서 이러는지는 모르겠지만 지금까지는 같은 정규군 소속이라 가급적 반격하지 않으려 했습니다.","JPN":"どうしてこんなことをするのかはわかりませんが、これまでは同じ正規軍の所属として、なるべく反撃は差し控えました。","ENG":"We don’t know why you’re doing this suddenly, but until now, we have been refraining from firing back out of consideration that we are part of the same official army.","TWN":"雖然不清楚你們發動攻擊的原因，但畢竟同屬正規軍，我已盡可能不反擊。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만 이 이상 공격을 이어간다면 반란군으로 규정하고 대응하겠습니다!","JPN":"ですがこれ以上攻撃を続けるのなら反乱軍と見なし、対応します！","ENG":"However, should you continue your assault, we will consider you as rebels and respond as such!","TWN":"不過若是再繼續發動攻擊，我們將裁定為叛軍，並予以處置！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_CHIEF","text":{"KOREA":"반란군?","JPN":"反乱軍？","ENG":"Rebels?","TWN":"叛軍？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_CHIEF","face":"UNIT_IDLE"},"R":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_CHIEF","text":{"KOREA":"바보 같은 말을 하는군. 우리가 바로 너희 같은 반란군을 체포하는 감찰부대다.","JPN":"バカげたことを言う。我々こそが貴様らのような反乱軍を逮捕する監察部隊だ。","ENG":"Don’t be stupid. We are the Inspection Corps that arrests rebels like you.","TWN":"說什麼蠢話，我們監察組就是要來逮捕你們這群叛軍的！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_CHIEF","face":"UNIT_IDLE"},"R":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"뭐, 뭐라고?","JPN":"な、なんだって？","ENG":"W-what did you just say?","TWN":"什…什麼？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_CHIEF","text":{"KOREA":"다시 말하지, 너희 델타 세븐은 권한 남용 및 쿠데타 혐의로 기소되었다.","JPN":"もう一度言おう、貴様らデルタセブンは権限の濫用及びクーデターの疑いで起訴された。","ENG":"Let me put in another way. Delta Seven has been charged with abuse of power and conspiring to attempt a coup.","TWN":"我再說一次，你們第七三角洲部隊，已經以濫用職權與涉嫌發動政變的罪名遭到起訴，"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_CHIEF","face":"UNIT_IDLE"},"R":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_CHIEF","text":{"KOREA":"그래서 우리가 너희들을 진압, 체포하러 온 거다.","JPN":"それで我々が貴様らを鎮圧、逮捕に来たわけだ。","ENG":"That is why we are here to suppress and arrest you.","TWN":"而我們是來逮捕你們的。"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_CHIEF","face":"UNIT_IDLE"},"R":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_CHIEF","text":{"KOREA":"여기 국방부에서 내려온 정식 명령서도 있다. 확인하려면 해라.","JPN":"こちらに国防省からの正式命令書もある。確認したければしろ。","ENG":"Here is the official warrant issued by the Department of Defense. You can check if you want.","TWN":"這是國防部正式發布的起訴書，你自己看吧！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_CHIEF","face":"UNIT_IDLE"},"R":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이건…… 진짜 원본이잖아?","JPN":"これは……本当に原本ではないか。","ENG":"This... is an authentic warrant!","TWN":"這……真的是正本？"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_CHIEF","text":{"KOREA":"알아보다니 다행이군. 그러니 다시 명령하겠다.","JPN":"それがわかってなによりだ。だから再び命令する。","ENG":"I’m glad to hear that you recognize it. As such, I am ordering you one more time.","TWN":"認得出來就好，我再說一次！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_CHIEF","face":"UNIT_IDLE"},"R":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"INSPECTOR_NPC_NULL_CHIEF","text":{"KOREA":"즉시 항복하고 무장을 해제하라, 그러지 않으면 전원 사살하겠다!","JPN":"ただちに降伏し、武装を解け。そうでなければ全員射殺する！","ENG":"Surrender immediately and lay down your weapons. Continue to resist and we will kill you all!","TWN":"立刻棄械投降！否則格殺勿論！"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INSPECTOR_NPC_NULL_CHIEF","face":"UNIT_IDLE"},"R":{"char_id":"INSPECTOR_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};